export function lerp(a, b, t) {
  return a + (b - a) * t;
}

export function pointAt(points, t) {
  if (!points || points.length === 0) return [0.5, 0.5];
  if (points.length === 1) return points[0];
  const segments = points.length - 1;
  const scaled = Math.max(0, Math.min(0.999999, t)) * segments;
  const i = Math.floor(scaled);
  const local = scaled - i;
  const a = points[i];
  const b = points[Math.min(points.length - 1, i + 1)];
  return [lerp(a[0], b[0], local), lerp(a[1], b[1], local)];
}

export function resampleStroke(points, count = 48) {
  const out = [];
  for (let i = 0; i < count; i++) {
    out.push(pointAt(points, count === 1 ? 0 : i / (count - 1)));
  }
  return out;
}

export function pathFromPoints(points, x, y, size, tension = 0.55, mod = (p) => p) {
  if (!points || points.length === 0) return '';
  const p = points.map((q, i) => mod(q, i));
  const toAbs = (q) => [x + q[0] * size, y + q[1] * size];
  let [sx, sy] = toAbs(p[0]);
  let d = `M ${sx.toFixed(2)} ${sy.toFixed(2)}`;
  for (let i = 0; i < p.length - 1; i++) {
    const p0 = p[Math.max(0, i - 1)];
    const p1 = p[i];
    const p2 = p[i + 1];
    const p3 = p[Math.min(p.length - 1, i + 2)];
    const cp1 = [p1[0] + (p2[0] - p0[0]) * tension / 6, p1[1] + (p2[1] - p0[1]) * tension / 6];
    const cp2 = [p2[0] - (p3[0] - p1[0]) * tension / 6, p2[1] - (p3[1] - p1[1]) * tension / 6];
    const [c1x, c1y] = toAbs(cp1);
    const [c2x, c2y] = toAbs(cp2);
    const [ex, ey] = toAbs(p2);
    d += ` C ${c1x.toFixed(2)} ${c1y.toFixed(2)}, ${c2x.toFixed(2)} ${c2y.toFixed(2)}, ${ex.toFixed(2)} ${ey.toFixed(2)}`;
  }
  return d;
}

export function glyphToSvgPaths(glyph, x = 0, y = 0, size = 512, tension = 0.55, mod = (p) => p) {
  return glyph.strokes.map((stroke, index) => {
    const d = pathFromPoints(stroke, x, y, size, tension, (p, i) => mod(p, i, index));
    return `<path d="${d}" vector-effect="non-scaling-stroke"/>`;
  }).join('\n  ');
}
